# --- 슬라이딩 윈도우 레이트리밋 (Lua 원자적, IP당 100 req/min) ---
from app.middleware.rate_limit import RateLimitMiddleware
app.add_middleware(RateLimitMiddleware)

@app.middleware("http")
async def csrf_middleware(request: Request, call_next):
    settings = get_settings()
    if request.method in {"GET", "HEAD", "OPTIONS"}:
        return await call_next(request)

    path = request.url.path
    csrf_exempt_prefixes = {
        "/api/v1/auth/login",
        "/api/v1/auth/register",
        "/api/v1/auth/refresh",
        "/api/v1/auth/csrf",
    }
    if path in csrf_exempt_prefixes:
        return await call_next(request)

    csrf_cookie = request.cookies.get(settings.AUTH_CSRF_COOKIE_NAME)
    csrf_header = request.headers.get(settings.AUTH_CSRF_HEADER_NAME)
    if not csrf_cookie or not csrf_header or csrf_cookie != csrf_header:
        return JSONResponse(
            status_code=403,
            content={"detail": "CSRF token missing or invalid"},
        )

    return await call_next(request)


@app.middleware("http")
async def response_envelope_middleware(request: Request, call_next):
    """응답을 전역 스키마로 래핑 (JSON만 적용)."""
    response = await call_next(request)

    # 문서/메트릭/스키마/스트리밍 응답은 제외
    if request.url.path in {"/metrics", "/docs", "/redoc", "/openapi.json"}:
        return response
    if isinstance(response, StreamingResponse):
        return response

    content_type = response.headers.get("content-type", "")
    if "application/json" not in content_type:
        return response

"""Authentication endpoints."""

from fastapi import APIRouter, Depends, HTTPException, status
from sqlalchemy.ext.asyncio import AsyncSession

from app.core.auth import get_current_user, get_current_user_optional
from app.core.database import get_db
from app.schemas.auth import (
    AuthResponse,
    LoginRequest,
    RefreshRequest,
    RegisterRequest,
)
from app.services.auth_service import login_user, refresh_tokens, register_user

router = APIRouter(prefix="/auth", tags=["auth"])

@router.post("/register", response_model=AuthResponse)
async def register(
    payload: RegisterRequest, db: AsyncSession = Depends(get_db)
) -> AuthResponse:
    return await register_user(
        db,
        email=payload.email,
        password=payload.password,
        username=payload.username,
        difficulty_level=payload.difficulty_level
    )


@router.post("/login", response_model=AuthResponse)
async def login(
    payload: LoginRequest, db: AsyncSession = Depends(get_db)
) -> AuthResponse:
    return await login_user(db, email=payload.email, password=payload.password)


@router.post("/refresh", response_model=AuthResponse)
async def refresh(
    payload: RefreshRequest, db: AsyncSession = Depends(get_db)
) -> AuthResponse:
    if not payload.refreshToken or not payload.refreshToken.strip():
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="refreshToken is required",
        )
    return await refresh_tokens(db, refresh_token=payload.refreshToken)


@router.post("/logout")
async def logout(
    user: dict | None = Depends(get_current_user_optional),
) -> dict:
    # Stateless JWT: client discards token. Keep endpoint for compatibility.
    if user:
        pass
    return {}


@router.get("/me")
async def get_me(
    user: dict = Depends(get_current_user),
) -> dict:
    return {
        "id": user["id"],
        "email": user["email"],
        "username": user["username"],
        "difficultyLevel": user.get("difficulty_level") or "beginner",
        "authenticated": True,
    }

def _validate_email_format(email: str) -> str:
    if not email:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="유효하지 않은 이메일 형식입니다.",
        )
    try:
        return str(_email_adapter.validate_python(email))
    except Exception:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="유효하지 않은 이메일 형식입니다.",
        )


def _validate_email_domain(email: str, blocked_domains: list[str]) -> str:
    normalized = _validate_email_format(email)
    domain = normalized.split("@", 1)[1].lower()
    for blocked in blocked_domains:
        if domain == blocked.lower():
            raise HTTPException(
                status_code=status.HTTP_400_BAD_REQUEST,
                detail=f"허용되지 않는 이메일 도메인입니다: {domain}",
            )
    return normalized

def _hash_token(token: str) -> str:
    return hashlib.sha256(token.encode("utf-8")).hexdigest()


async def _require_redis() -> "redis.Redis":
    cache = await get_redis_cache()
    if not cache.client:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis unavailable for token management",
        )
    return cache.client


async def _store_refresh_token(*, user_id: int, jti: str, token_hash: str, ttl: int) -> None:
    client = await _require_redis()
    token_key = f"auth:rt:{jti}"
    user_key = f"auth:rt:uid:{user_id}"
    async with client.pipeline(transaction=True) as pipe:
        pipe.setex(token_key, ttl, token_hash)

