 20→export function UserProvider({ children }) {
 21→  const [user, setUser] = useState(null);
 22→  const [settings, setSettings] = useState(() => {
 23→    const saved = localStorage.getItem('userSettings');
 24→    if (saved) {
 25→      try {
 26→        return { ...DEFAULT_USER_SETTINGS, ...JSON.parse(saved) };
 27→      } catch {
 28→        return DEFAULT_USER_SETTINGS;
 29→      }
 30→    }
 31→    return DEFAULT_USER_SETTINGS;
 32→  });
 33→  const [isLoading, setIsLoading] = useState(true);
 34→
 35→  // Save settings to localStorage
 36→  useEffect(() => {
 37→    localStorage.setItem('userSettings', JSON.stringify(settings));
 38→  }, [settings]);
 39→
 40→  // Initialize user (check for token and restore user info)
 41→  useEffect(() => {
 42→    const token = localStorage.getItem('token');
 43→    if (token) {
 44→      authApi.getMe(token)
 45→        .then(data => {
 46→          setUser({
 47→            id: data.id,
 48→            email: data.email,
 49→            username: data.username,
 50→            isAuthenticated: true,
 51→          });
 52→        })
 53→        .catch(() => {
 54→          // 토큰 만료 또는 유효하지 않음 → 제거
 55→          localStorage.removeItem('token');
 56→          localStorage.removeItem('refreshToken');
 57→        })
 58→        .finally(() => setIsLoading(false));
 59→    } else {
 60→      setIsLoading(false);
 61→    }
 62→  }, []);
 63→
 64→  // 401 응답 시 자동 로그아웃 (client.js에서 이벤트 발행)
 65→  useEffect(() => {
 66→    const handleForceLogout = () => setUser(null);
 67→    window.addEventListener('auth:logout', handleForceLogout);
 68→    return () => window.removeEventListener('auth:logout', handleForceLogout);
 69→  }, []);
 70→
 71→  const updateSettings = useCallback((newSettings) => {
 72→    setSettings((prev) => ({ ...prev, ...newSettings }));
 73→  }, []);
 74→
 75→  const setDifficulty = useCallback((difficulty) => {
 76→    setSettings((prev) => ({ ...prev, difficulty }));
 77→  }, []);
 78→
 79→  const completeOnboarding = useCallback(() => {
 80→    setSettings((prev) => ({ ...prev, hasCompletedOnboarding: true }));
 81→  }, []);
 82→
 83→  const addBookmark = useCallback((item) => {
 84→    setSettings((prev) => ({
 85→      ...prev,
 86→      bookmarks: [...prev.bookmarks.filter((b) => b.id !== item.id), item],
 87→    }));
 88→  }, []);
 89→
 90→  const removeBookmark = useCallback((itemId) => {
 91→    setSettings((prev) => ({
 92→      ...prev,
 93→      bookmarks: prev.bookmarks.filter((b) => b.id !== itemId),
 94→    }));
 95→  }, []);
 96→
 97→  const addToHistory = useCallback((item) => {
 98→    setSettings((prev) => ({
 99→      ...prev,
100→      history: [
101→        item,
102→        ...prev.history.filter((h) => h.id !== item.id).slice(0, 49),
103→      ],
104→    }));
105→  }, []);
106→
107→  const login = useCallback((authResponse) => {
108→    setUser({
109→      id: authResponse.user?.id,
110→      email: authResponse.user?.email,
111→      username: authResponse.user?.username,
112→      isAuthenticated: true,
113→    });
114→    localStorage.setItem('token', authResponse.accessToken);
115→    if (authResponse.refreshToken) {
116→      localStorage.setItem('refreshToken', authResponse.refreshToken);
117→    }
118→  }, []);
119→
120→  const logout = useCallback(() => {
121→    setUser(null);
122→    localStorage.removeItem('token');
123→    localStorage.removeItem('refreshToken');
124→  }, []);
125→
126→  const value = useMemo(() => ({
127→    user,
128→    settings,
129→    isLoading,
130→    updateSettings,
131→    setDifficulty,
132→    completeOnboarding,
133→    addBookmark,
134→    removeBookmark,
135→    addToHistory,
136→    login,
137→    logout,
138→  }), [
139→    user, settings, isLoading, updateSettings, setDifficulty,
140→    completeOnboarding, addBookmark, removeBookmark, addToHistory,
141→    login, logout,
142→  ]);
143→
144→  return (
145→    <UserContext.Provider value={value}>
146→      {children}
147→    </UserContext.Provider>
148→  );
149→}
