@router.post("/refresh", response_model=AuthResponse)
async def refresh(request: Request, db: AsyncSession = Depends(get_db)) -> Response:
    # ✅ 요청 쿠키에서 refreshToken 추출
    refresh_token = request.cookies.get("refresh_token")
    if not refresh_token or not refresh_token.strip():
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="refreshToken is required",
        )

    tokens = await refresh_tokens(db, refresh_token=refresh_token)

    response = Response(content=tokens.model_dump_json(), media_type="application/json")
    response.set_cookie(
        key="access_token",
        value=tokens.accessToken,
        max_age=3600,
        httponly=True,
        secure=True,
        samesite="strict",
        path="/",
    )
    response.set_cookie(
        key="refresh_token",
        value=tokens.refreshToken,
        max_age=604800,
        httponly=True,
        secure=True,
        samesite="strict",
        path="/api/v1/auth",
