426→  const totalSteps = STEP_CONFIGS.length;
427→
428→  useEffect(() => {
429→    if (!caseId) {
430→      setContextInfo(null);
431→      return;
432→    }
433→
434→    const currentStepConfig = STEP_CONFIGS[currentStep];
435→    const currentStepData = data?.steps?.[currentStepConfig.key];
436→    let fullContextText = '';
437→
438→    // If data and steps exist, extract the current step's title and content for the chatbot context
439→    if (currentStepData) {
440→      const stepTitle = currentStepData.title || currentStepConfig.title;
441→      const stepContent = currentStepData.content || '';
442→
443→      fullContextText = `[${stepTitle}]\n`;
444→
445→      // Also include bullets if they exist (especially for the 'caution' or 'summary' steps)
446→      if (currentStepData.bullets && currentStepData.bullets.length > 0) {
447→        fullContextText += currentStepData.bullets.map((b) => `- ${b}`).join('\n') + '\n\n';
448→      }
449→
450→      fullContextText += stepContent;
451→    }
452→
453→    setContextInfo({
454→      type: 'case',
455→      id: Number(caseId),
456→      stepContent: fullContextText,
457→      stepKey: currentStepConfig.key,
458→      stepTitle: currentStepData?.title || currentStepConfig.title,
459→      stepTag: currentStepConfig.tag,
460→      sourcePage: 'narrative',
461→    });
462→
463→    return () => setContextInfo(null);
464→  }, [caseId, data, currentStep, setContextInfo]);
465→
466→  const clearResumeState = useCallback(() => {
467→    if (!caseId) return;
468→    try {
469→      localStorage.removeItem(getResumeStorageKey(caseId));
470→    } catch {
471→      // ignore localStorage errors
472→    }
473→  }, [caseId]);
474→
475→  const saveResumeState = useCallback((stepIndex) => {
476→    if (!caseId) return;
477→    try {
478→      localStorage.setItem(
479→        getResumeStorageKey(caseId),
480→        JSON.stringify({
481→          stepIndex,
482→          scrollY: window.scrollY || 0,
483→          updatedAt: new Date().toISOString(),
484→        }),
485→      );
486→    } catch {
487→      // ignore localStorage errors
488→    }
489→  }, [caseId]);
490→
491→  const readValidResumeState = useCallback(() => {
492→    if (!caseId) return null;
493→    try {
494→      const raw = localStorage.getItem(getResumeStorageKey(caseId));
495→      if (!raw) return null;
496→
497→      const parsed = JSON.parse(raw);
498→      const savedAt = Date.parse(parsed?.updatedAt || '');
499→      if (!Number.isFinite(savedAt) || Date.now() - savedAt > RESUME_TTL_MS) {
500→        clearResumeState();
501→        return null;
502→      }
503→
504→      const parsedStep = Number.isInteger(parsed?.stepIndex) ? parsed.stepIndex : 0;
505→      const safeStepIndex = Math.min(Math.max(parsedStep, 0), totalSteps - 1);
506→      const safeScrollY = Math.max(0, Number(parsed?.scrollY || 0));
507→
508→      return {
509→        stepIndex: safeStepIndex,
510→        scrollY: safeScrollY,
511→      };
512→    } catch {
513→      clearResumeState();
514→      return null;
515→    }
516→  }, [caseId, clearResumeState, totalSteps]);
517→
518→  const applyResumeState = useCallback((stepIndex, scrollY = 0) => {
519→    setDirection(0);
520→    setCurrentStep(stepIndex);
521→    requestAnimationFrame(() => {
522→      requestAnimationFrame(() => {
523→        window.scrollTo({ top: scrollY, behavior: 'auto' });
524→      });
525→    });
526→  }, []);
527→
528→  const upsertLearningProgress = useCallback(async (status, progressPercent) => {
529→    const parsedCaseId = Number(caseId);
530→    if (!Number.isInteger(parsedCaseId) || parsedCaseId <= 0) return;
531→
532→    try {
533→      await learningApi.upsertProgress({
534→        content_type: 'case',
535→        content_id: parsedCaseId,
536→        status,
537→        progress_percent: progressPercent,
538→      });
539→    } catch {
540→      // 학습 로그 실패는 화면 흐름을 막지 않음
541→    }
542→  }, [caseId]);
543→
544→  useEffect(() => {
545→    hasRestoredResumeRef.current = false;
546→    hasLoggedInProgressRef.current = false;
547→    setRewardViewState('none');
548→    setRewardData(null);
549→    setRewardError('');
550→    setPendingResumeState(null);
551→    setIsResumeDialogOpen(false);
552→  }, [caseId]);
553→
554→  useEffect(() => {
555→    if (!caseId) {
556→      setError('케이스 ID가 없습니다.');
557→      setIsLoading(false);
558→      return;
559→    }
560→
561→    setIsLoading(true);
562→    setError(null);
563→
564→    narrativeApi.getNarrative(caseId)
565→      .then((response) => {
566→        if (!response || !response.steps) {
567→          throw new Error('내러티브 데이터가 없습니다.');
568→        }
569→        setData(response);
570→      })
571→      .catch((fetchError) => {
572→        setError(fetchError?.message || '내러티브 데이터를 불러오지 못했습니다.');
573→      })
574→      .finally(() => setIsLoading(false));
575→  }, [caseId]);
576→
577→  const stepConfig = STEP_CONFIGS[currentStep];
578→  const stepData = data?.steps?.[stepConfig.key];
579→  const stepTitle = stepData?.title || stepConfig.title;
580→  const isLastStep = currentStep === totalSteps - 1;
581→
582→  useEffect(() => {
583→    if (!caseId || !data || isLoading || error || hasLoggedInProgressRef.current) return;
584→    hasLoggedInProgressRef.current = true;
585→    upsertLearningProgress('in_progress', 20);
