587→
588→  useEffect(() => {
589→    if (!caseId || !data || isLoading || error || hasRestoredResumeRef.current) return;
590→
591→    let cancelled = false;
592→
593→    const restoreEntry = async () => {
594→      const savedResume = readValidResumeState();
595→
596→      if (!savedResume || savedResume.stepIndex <= 0) {
597→        hasRestoredResumeRef.current = true;
598→        applyResumeState(0, 0);
599→        return;
600→      }
601→
602→      let isCompleted = false;
603→      try {
604→        const progressRes = await learningApi.getProgress({ contentType: 'case' });
605→        const progressList = Array.isArray(progressRes?.data) ? progressRes.data : [];
606→        const currentCaseProgress = progressList.find((item) => Number(item.content_id) === Number(caseId));
607→        isCompleted = currentCaseProgress?.status === 'completed';
608→      } catch {
609→        // 학습 진도 조회 실패 시 로컬 resume 기준으로 처리
610→      }
611→
612→      if (cancelled) return;
613→
614→      if (isCompleted) {
615→        clearResumeState();
616→        hasRestoredResumeRef.current = true;
617→        applyResumeState(0, 0);
618→        return;
619→      }
620→
621→      setPendingResumeState(savedResume);
622→      setIsResumeDialogOpen(true);
623→    };
624→
625→    restoreEntry();
626→
627→    return () => {
628→      cancelled = true;
629→    };
630→  }, [applyResumeState, caseId, clearResumeState, data, error, isLoading, readValidResumeState]);
631→
632→  const handleResumeFromBeginning = useCallback(() => {
633→    clearResumeState();
634→    hasRestoredResumeRef.current = true;
635→    setPendingResumeState(null);
636→    setIsResumeDialogOpen(false);
637→    applyResumeState(0, 0);
638→  }, [applyResumeState, clearResumeState]);
639→
640→  const handleResumeFromSavedPoint = useCallback(() => {
641→    const stepIndex = pendingResumeState?.stepIndex || 0;
642→    const scrollY = pendingResumeState?.scrollY || 0;
643→    hasRestoredResumeRef.current = true;
644→    setPendingResumeState(null);
645→    setIsResumeDialogOpen(false);
646→    applyResumeState(stepIndex, scrollY);
647→  }, [applyResumeState, pendingResumeState]);
648→
649→  useEffect(() => {
650→    if (!caseId || !data || isLoading || error || !hasRestoredResumeRef.current) return;
651→    saveResumeState(currentStep);
652→  }, [caseId, currentStep, data, error, isLoading, saveResumeState]);
653→
654→  useEffect(() => {
655→    if (!caseId || !data || isLoading || error || !hasRestoredResumeRef.current) return undefined;
656→
657→    const handleScroll = () => {
658→      if (scrollThrottleTimerRef.current) return;
659→      scrollThrottleTimerRef.current = window.setTimeout(() => {
660→        saveResumeState(currentStep);
661→        scrollThrottleTimerRef.current = null;
662→      }, 250);
663→    };
664→
665→    window.addEventListener('scroll', handleScroll, { passive: true });
666→    return () => {
667→      window.removeEventListener('scroll', handleScroll);
668→      if (scrollThrottleTimerRef.current) {
669→        window.clearTimeout(scrollThrottleTimerRef.current);
670→        scrollThrottleTimerRef.current = null;
671→      }
672→    };
673→  }, [caseId, currentStep, data, error, isLoading, saveResumeState]);
674→
675→  const goToStep = (nextIndex) => {
676→    if (nextIndex < 0 || nextIndex >= totalSteps) return;
677→    setDirection(nextIndex > currentStep ? 1 : -1);
678→    setCurrentStep(nextIndex);
679→  };
680→
681→  const goPrev = () => {
682→    goToStep(currentStep - 1);
683→  };
684→
685→  const goNext = async () => {
686→    if (!isLastStep) {
687→      goToStep(currentStep + 1);
688→      return;
689→    }
690→
691→    try {
692→      setRewardError('');
693→      const reward = await claimReward(Number(caseId));
694→      if (reward) {
695→        setRewardData(reward);
696→        setRewardViewState('success');
697→        clearResumeState();
698→        upsertLearningProgress('completed', 100);
699→      }
700→    } catch (claimError) {
701→      const message = claimError?.message || '보상 청구에 실패했습니다.';
702→      if (message.includes('이미')) {
703→        setRewardData(null);
704→        setRewardViewState('already_claimed');
705→        clearResumeState();
706→        upsertLearningProgress('completed', 100);
707→        return;
708→      }
709→      setRewardError(message);
710→    }
711→  };
712→
713→  const handleDragEnd = (_, info) => {
714→    const offsetX = info?.offset?.x ?? 0;
715→    const velocityX = info?.velocity?.x ?? 0;
716→
717→    if (offsetX <= -SWIPE_THRESHOLD || velocityX <= -SWIPE_VELOCITY) {
718→      if (!isLastStep) goToStep(currentStep + 1);
719→      return;
720→    }
721→
722→    if (offsetX >= SWIPE_THRESHOLD || velocityX >= SWIPE_VELOCITY) {
723→      goToStep(currentStep - 1);
724→    }
725→  };
726→
727→  const closeReward = () => {
