748→            onClick={() => navigate('/search')}
749→            className="mt-4 rounded-xl bg-primary px-4 py-2 text-sm font-semibold text-white"
750→          >
751→            검색으로 돌아가기
752→          </button>
753→        </div>
754→      </div>
