764→          <div className="mb-3 flex items-center justify-between">
765→            <button
766→              type="button"
767→              onClick={() => navigate(-1)}
768→              className="flex items-center gap-1 text-sm font-medium text-text-secondary transition hover:text-text-primary"
769→            >
770→              <span className="text-lg">‹</span>
